COMMENT ON TABLE "public"."message_outbox" IS E'消息投递外盒表\n用于保障通知/聊天事件可靠异步投递';
COMMENT ON COLUMN "public"."message_outbox"."id" IS E'主键ID';
COMMENT ON COLUMN "public"."message_outbox"."domain" IS E'事件域（1=通知,2=聊天）';
