COMMENT ON COLUMN "public"."message_ws_metric"."resync_success_count" IS E'补偿成功次数（afterSeq 查询成功返回）';
COMMENT ON COLUMN "public"."message_ws_metric"."created_at" IS E'创建时间';
COMMENT ON COLUMN "public"."message_ws_metric"."updated_at" IS E'更新时间';
COMMENT ON TABLE "public"."notification_delivery" IS E'通知投递结果表\n为通知域记录 outbox 消费后的业务结果，避免技术消费状态与最终投递结果混淆';
COMMENT ON COLUMN "public"."notification_delivery"."id" IS E'主键 ID';
COMMENT ON COLUMN "public"."notification_delivery"."outbox_id" IS E'关联的 outbox 事件 ID\n当前采用一条 outbox 对应一条 delivery 记录，并在重试过程中持续更新';
COMMENT ON COLUMN "public"."notification_delivery"."biz_key" IS E'业务幂等键\n与 message_outbox.bizKey 对齐，便于运营和日志按同一键排障';
COMMENT ON COLUMN "public"."notification_delivery"."notification_type" IS E'通知类型\n与 MessageNotificationTypeEnum 保持一致；异常数据兼容场景允许为空';
COMMENT ON COLUMN "public"."notification_delivery"."receiver_user_id" IS E'接收用户 ID\n从通知 payload 最小解析得到；无效 payload 场景允许为空';
COMMENT ON COLUMN "public"."notification_delivery"."notification_id" IS E'关联的站内通知 ID\n仅在 DELIVERED 场景可回填，跳过或失败场景保持为空';
COMMENT ON COLUMN "public"."notification_delivery"."status" IS E'业务投递结果\n取值为 DELIVERED / FAILED / RETRYING / SKIPPED_DUPLICATE / SKIPPED_SELF / SKIPPED_PREFERENCE';
COMMENT ON COLUMN "public"."notification_delivery"."retry_count" IS E'当前重试次数\n与 message_outbox.retryCount 同步，用于区分初次失败和多次重试';
COMMENT ON COLUMN "public"."notification_delivery"."failure_reason" IS E'最近一次失败原因\n仅在 FAILED / RETRYING 场景记录，跳过和成功场景为空';
COMMENT ON COLUMN "public"."notification_delivery"."last_attempt_at" IS E'最近一次业务投递尝试时间\n无论成功、跳过还是失败重试，都会在每次业务结果更新时刷新';
COMMENT ON COLUMN "public"."notification_delivery"."created_at" IS E'创建时间';
COMMENT ON COLUMN "public"."notification_delivery"."updated_at" IS E'更新时间';
COMMENT ON TABLE "public"."notification_preference" IS E'通知偏好表\n只记录用户对站内通知类型的显式覆盖配置；未写入的类型继续回退到默认策略';
COMMENT ON COLUMN "public"."notification_preference"."id" IS E'主键 ID';
COMMENT ON COLUMN "public"."notification_preference"."user_id" IS E'用户 ID\n与 app_user 一对多关联，只存当前用户主动调整过的通知类型';
COMMENT ON COLUMN "public"."notification_preference"."notification_type" IS E'通知类型\n与 MessageNotificationTypeEnum 保持一致，当前第一阶段只按类型维度控制偏好';
COMMENT ON COLUMN "public"."notification_preference"."is_enabled" IS E'是否启用\ntrue / false 仅代表显式覆盖值；若与默认值相同，业务层会删除该行而不是长期保留冗余记录';
COMMENT ON COLUMN "public"."notification_preference"."created_at" IS E'创建时间';
COMMENT ON COLUMN "public"."notification_preference"."updated_at" IS E'更新时间';
COMMENT ON TABLE "public"."notification_template" IS E'通知模板表\n为站内通知提供可配置的 title / content 模板，并保留类型到模板键的一对一稳定映射';
COMMENT ON COLUMN "public"."notification_template"."id" IS E'主键 ID';
COMMENT ON COLUMN "public"."notification_template"."template_key" IS E'模板唯一键\n当前由通知类型推导生成，用于跨环境稳定引用与排障';
COMMENT ON COLUMN "public"."notification_template"."notification_type" IS E'通知类型\n与 MessageNotificationTypeEnum 保持一致，当前一类通知只允许一份模板';
COMMENT ON COLUMN "public"."notification_template"."title_template" IS E'标题模板\n渲染后需满足 user_notification.title 的长度约束';
COMMENT ON COLUMN "public"."notification_template"."content_template" IS E'正文模板\n渲染后需满足 user_notification.content 的长度约束';
COMMENT ON COLUMN "public"."notification_template"."is_enabled" IS E'是否启用\n关闭后通知主链路会自动回退到业务方提供的 fallback 文案';
COMMENT ON COLUMN "public"."notification_template"."remark" IS E'备注\n仅供运营与排障说明使用，不参与渲染';
COMMENT ON COLUMN "public"."notification_template"."created_at" IS E'创建时间';
COMMENT ON COLUMN "public"."notification_template"."updated_at" IS E'更新时间';
COMMENT ON TABLE "public"."sensitive_word" IS E'通用敏感词表 - 存储敏感词信息，用于内容过滤和审核';
COMMENT ON COLUMN "public"."sensitive_word"."id" IS E'主键ID';
